import React, { useState } from 'react';
import { Link } from 'react-router-dom';

const NavigationBar = () => {
  const [chainState, setChainState] = useState('ethereum');

  const toggleChain = () => {
    setChainState(prevState => prevState === 'ethereum' ? 'pulsechain' : 'ethereum');
  };

  return (
    <nav className="flex justify-between items-center px-5 py-3 bg-black text-white font-sans">
      <div className="flex space-x-6">
        <Link to="/" className="text-white no-underline">LookIntoMaxi</Link>
        <Link to="/delta-discounts" className="text-white no-underline">Δ Discounts</Link>
        <Link to="/percent-discounts" className="text-white no-underline">% Discounts</Link>
        <Link to="/arbs" className="text-white no-underline">Arbs</Link>
        <Link to="/apy" className="text-white no-underline">Apy</Link>
        <Link to="/leagues" className="text-white no-underline">Leagues</Link>
        <Link to="/gas" className="text-white no-underline">Gas</Link>
      </div>
      <div className="flex items-center space-x-4">
        <button 
          onClick={toggleChain} 
          className="bg-white text-black rounded px-3 py-1 text-lg"
        >
          {chainState === 'ethereum' ? '▼' : '〰️'}
        </button>
        <Link 
          to="/buy" 
          className="border border-white rounded px-4 py-1 text-white no-underline hover:bg-white hover:text-black transition-colors duration-300"
        >
          Buy
        </Link>
      </div>
    </nav>
  );
};

export default NavigationBar;
